BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?binName ?elem ?elemName WHERE {
  ?bin vocab:NamedElement_name ?binName . 
  FILTER(CONTAINS(LCASE(STR(?binName)), LCASE("holding_bin")))
  ?bin vocab:Element_ownedElement ?elem .
  OPTIONAL { ?elem vocab:NamedElement_name ?elemName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?binName ?nestedPkg ?nestedName WHERE {
  ?bin vocab:NamedElement_name ?binName . 
  FILTER(CONTAINS(LCASE(STR(?binName)), LCASE("holding_bin")))
  ?bin vocab:Package_nestedPackage ?nestedPkg .
  OPTIONAL { ?nestedPkg vocab:NamedElement_name ?nestedName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?yearName ?elem ?elemName WHERE {
  ?yearPkg vocab:NamedElement_name ?yearName . 
  FILTER(CONTAINS(LCASE(STR(?yearName)), "YY_2016") || CONTAINS(LCASE(STR(?yearName)), "YY_2017"))
  ?yearPkg vocab:Element_ownedElement ?elem .
  OPTIONAL { ?elem vocab:NamedElement_name ?elemName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?yearName ?elem ?elemName WHERE {
  ?yearPkg vocab:NamedElement_name ?yearName . 
  FILTER(CONTAINS(LCASE(STR(?yearName)), "YY_2016") || CONTAINS(LCASE(STR(?yearName)), "YY_2017"))
  ?yearPkg vocab:Package_packagedElement ?elem .
  OPTIONAL { ?elem vocab:NamedElement_name ?elemName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?yearName ?elem ?elemName ?qualifiedName WHERE {
  ?yearPkg vocab:NamedElement_name ?yearName .
  FILTER(CONTAINS(STR(?yearName), "YY_2017"))
  ?yearPkg vocab:Element_ownedElement+ ?elem .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?elemName }
  OPTIONAL { ?elem vocab:NamedElement_qualifiedName ?qualifiedName }
}
LIMIT 50
